import React, { useState, useEffect } from 'react';
import { LineChart, Line, PieChart, Pie, Cell, XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer } from 'recharts';

// Icon components
const PlusCircle = () => <span style={{ fontSize: '1.2em' }}>➕</span>;
const TrendingDown = () => <span style={{ fontSize: '1.5em' }}>📉</span>;
const TrendingUp = () => <span style={{ fontSize: '1.5em' }}>📈</span>;
const DollarSign = () => <span style={{ fontSize: '1.5em' }}>💰</span>;
const Calendar = () => <span style={{ fontSize: '1.5em' }}>📅</span>;
const Filter = () => <span style={{ fontSize: '1.2em' }}>🔍</span>;
const Download = () => <span style={{ fontSize: '1em' }}>⬇️</span>;
const Trash2 = () => <span style={{ fontSize: '1em' }}>🗑️</span>;
const Edit3 = () => <span style={{ fontSize: '1em' }}>✏️</span>;

const ExpensesTracker = () => {
  const [expenses, setExpenses] = useState([]);
  const [showAddForm, setShowAddForm] = useState(false);
  const [filterCategory, setFilterCategory] = useState('all');
  const [filterPeriod, setFilterPeriod] = useState('all');
  const [editingId, setEditingId] = useState(null);

  const [formData, setFormData] = useState({
    description: '',
    amount: '',
    category: 'food',
    date: new Date().toISOString().split('T')[0],
    notes: ''
  });

  const categories = [
    { value: 'food', label: 'Food & Dining', color: '#3b82f6' },
    { value: 'transport', label: 'Transportation', color: '#10b981' },
    { value: 'utilities', label: 'Utilities', color: '#f59e0b' },
    { value: 'entertainment', label: 'Entertainment', color: '#ec4899' },
    { value: 'healthcare', label: 'Healthcare', color: '#8b5cf6' },
    { value: 'shopping', label: 'Shopping', color: '#ef4444' },
    { value: 'education', label: 'Education', color: '#06b6d4' },
    { value: 'other', label: 'Other', color: '#6b7280' }
  ];

  useEffect(() => {
    loadExpenses();
  }, []);

  const loadExpenses = async () => {
    try {
      const result = await window.storage.get('finshield-expenses');
      if (result) {
        setExpenses(JSON.parse(result.value));
      }
    } catch (error) {
      console.log('No expenses found, starting fresh');
    }
  };

  const saveExpenses = async (newExpenses) => {
    try {
      await window.storage.set('finshield-expenses', JSON.stringify(newExpenses));
      setExpenses(newExpenses);
    } catch (error) {
      console.error('Error saving expenses:', error);
    }
  };

  const handleSubmit = () => {
    if (!formData.description || !formData.amount || !formData.date) {
      alert('Please fill in all required fields');
      return;
    }

    if (editingId) {
      const updated = expenses.map(exp => 
        exp.id === editingId 
          ? { ...formData, id: editingId, amount: parseFloat(formData.amount) }
          : exp
      );
      saveExpenses(updated);
      setEditingId(null);
    } else {
      const newExpense = {
        ...formData,
        id: Date.now(),
        amount: parseFloat(formData.amount)
      };
      saveExpenses([...expenses, newExpense]);
    }

    setFormData({
      description: '',
      amount: '',
      category: 'food',
      date: new Date().toISOString().split('T')[0],
      notes: ''
    });
    setShowAddForm(false);
  };

  const handleEdit = (expense) => {
    setFormData({
      description: expense.description,
      amount: expense.amount.toString(),
      category: expense.category,
      date: expense.date,
      notes: expense.notes || ''
    });
    setEditingId(expense.id);
    setShowAddForm(true);
  };

  const handleDelete = (id) => {
    if (confirm('Are you sure you want to delete this expense?')) {
      saveExpenses(expenses.filter(exp => exp.id !== id));
    }
  };

  const getFilteredExpenses = () => {
    let filtered = [...expenses];

    if (filterCategory !== 'all') {
      filtered = filtered.filter(exp => exp.category === filterCategory);
    }

    if (filterPeriod !== 'all') {
      const now = new Date();
      const expenseDate = (exp) => new Date(exp.date);

      filtered = filtered.filter(exp => {
        const date = expenseDate(exp);
        switch (filterPeriod) {
          case 'today':
            return date.toDateString() === now.toDateString();
          case 'week':
            const weekAgo = new Date(now.getTime() - 7 * 24 * 60 * 60 * 1000);
            return date >= weekAgo;
          case 'month':
            return date.getMonth() === now.getMonth() && date.getFullYear() === now.getFullYear();
          case 'year':
            return date.getFullYear() === now.getFullYear();
          default:
            return true;
        }
      });
    }

    return filtered.sort((a, b) => new Date(b.date) - new Date(a.date));
  };

  const filteredExpenses = getFilteredExpenses();
  const totalExpenses = filteredExpenses.reduce((sum, exp) => sum + exp.amount, 0);

  const getCategoryData = () => {
    const categoryTotals = {};
    filteredExpenses.forEach(exp => {
      categoryTotals[exp.category] = (categoryTotals[exp.category] || 0) + exp.amount;
    });

    return Object.entries(categoryTotals).map(([category, value]) => ({
      name: categories.find(c => c.value === category)?.label || category,
      value: value,
      color: categories.find(c => c.value === category)?.color || '#6b7280'
    }));
  };

  const getTrendData = () => {
    const dailyTotals = {};
    filteredExpenses.forEach(exp => {
      const date = exp.date;
      dailyTotals[date] = (dailyTotals[date] || 0) + exp.amount;
    });

    return Object.entries(dailyTotals)
      .sort(([a], [b]) => new Date(a) - new Date(b))
      .slice(-30)
      .map(([date, amount]) => ({
        date: new Date(date).toLocaleDateString('en-US', { month: 'short', day: 'numeric' }),
        amount: amount
      }));
  };

  const exportToCSV = () => {
    const headers = ['Date', 'Description', 'Category', 'Amount', 'Notes'];
    const rows = filteredExpenses.map(exp => [
      exp.date,
      exp.description,
      categories.find(c => c.value === exp.category)?.label,
      exp.amount,
      exp.notes || ''
    ]);

    const csv = [headers, ...rows].map(row => row.join(',')).join('\n');
    const blob = new Blob([csv], { type: 'text/csv' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `finshield-expenses-${new Date().toISOString().split('T')[0]}.csv`;
    a.click();
  };

  return (
    <div className="min-h-screen bg-gradient-to-br from-slate-900 via-blue-900 to-slate-900 p-6">
      <div className="max-w-7xl mx-auto">
        {/* Header */}
        <div className="mb-8">
          <h1 className="text-4xl font-bold text-white mb-2 flex items-center gap-3">
            <DollarSign />
            FinShield Expenses
          </h1>
          <p className="text-blue-200">Track and manage your finances with ease</p>
        </div>

        {/* Stats Cards */}
        <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-8">
          <div className="bg-white/10 backdrop-blur-lg rounded-xl p-6 border border-white/20">
            <div className="flex items-center justify-between">
              <div>
                <p className="text-blue-200 text-sm mb-1">Total Expenses</p>
                <p className="text-3xl font-bold text-white">${totalExpenses.toFixed(2)}</p>
              </div>
              <TrendingDown className="w-12 h-12 text-red-400" />
            </div>
          </div>

          <div className="bg-white/10 backdrop-blur-lg rounded-xl p-6 border border-white/20">
            <div className="flex items-center justify-between">
              <div>
                <p className="text-blue-200 text-sm mb-1">Transactions</p>
                <p className="text-3xl font-bold text-white">{filteredExpenses.length}</p>
              </div>
              <Calendar className="w-12 h-12 text-green-400" />
            </div>
          </div>

          <div className="bg-white/10 backdrop-blur-lg rounded-xl p-6 border border-white/20">
            <div className="flex items-center justify-between">
              <div>
                <p className="text-blue-200 text-sm mb-1">Average</p>
                <p className="text-3xl font-bold text-white">
                  ${filteredExpenses.length > 0 ? (totalExpenses / filteredExpenses.length).toFixed(2) : '0.00'}
                </p>
              </div>
              <TrendingUp className="w-12 h-12 text-blue-400" />
            </div>
          </div>
        </div>

        {/* Charts */}
        {filteredExpenses.length > 0 && (
          <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 mb-8">
            <div className="bg-white/10 backdrop-blur-lg rounded-xl p-6 border border-white/20">
              <h3 className="text-xl font-semibold text-white mb-4">Spending by Category</h3>
              <ResponsiveContainer width="100%" height={300}>
                <PieChart>
                  <Pie
                    data={getCategoryData()}
                    cx="50%"
                    cy="50%"
                    labelLine={false}
                    label={({ name, percent }) => `${name} ${(percent * 100).toFixed(0)}%`}
                    outerRadius={100}
                    fill="#8884d8"
                    dataKey="value"
                  >
                    {getCategoryData().map((entry, index) => (
                      <Cell key={`cell-${index}`} fill={entry.color} />
                    ))}
                  </Pie>
                  <Tooltip />
                </PieChart>
              </ResponsiveContainer>
            </div>

            <div className="bg-white/10 backdrop-blur-lg rounded-xl p-6 border border-white/20">
              <h3 className="text-xl font-semibold text-white mb-4">Spending Trend</h3>
              <ResponsiveContainer width="100%" height={300}>
                <LineChart data={getTrendData()}>
                  <CartesianGrid strokeDasharray="3 3" stroke="#ffffff20" />
                  <XAxis dataKey="date" stroke="#93c5fd" />
                  <YAxis stroke="#93c5fd" />
                  <Tooltip 
                    contentStyle={{ backgroundColor: '#1e293b', border: '1px solid #475569' }}
                    labelStyle={{ color: '#93c5fd' }}
                  />
                  <Line type="monotone" dataKey="amount" stroke="#3b82f6" strokeWidth={2} />
                </LineChart>
              </ResponsiveContainer>
            </div>
          </div>
        )}

        {/* Controls */}
        <div className="bg-white/10 backdrop-blur-lg rounded-xl p-6 border border-white/20 mb-6">
          <div className="flex flex-wrap gap-4 items-center justify-between">
            <div className="flex flex-wrap gap-4">
              <div className="flex items-center gap-2">
                <Filter />
                <select
                  value={filterCategory}
                  onChange={(e) => setFilterCategory(e.target.value)}
                  className="bg-white/20 text-white border border-white/30 rounded-lg px-3 py-2 focus:outline-none focus:ring-2 focus:ring-blue-500"
                >
                  <option value="all">All Categories</option>
                  {categories.map(cat => (
                    <option key={cat.value} value={cat.value}>{cat.label}</option>
                  ))}
                </select>
              </div>

              <select
                value={filterPeriod}
                onChange={(e) => setFilterPeriod(e.target.value)}
                className="bg-white/20 text-white border border-white/30 rounded-lg px-3 py-2 focus:outline-none focus:ring-2 focus:ring-blue-500"
              >
                <option value="all">All Time</option>
                <option value="today">Today</option>
                <option value="week">This Week</option>
                <option value="month">This Month</option>
                <option value="year">This Year</option>
              </select>
            </div>

            <div className="flex gap-3">
              <button
                onClick={exportToCSV}
                className="flex items-center gap-2 bg-green-600 hover:bg-green-700 text-white px-4 py-2 rounded-lg transition"
              >
                <Download />
                Export
              </button>
              <button
                onClick={() => {
                  setShowAddForm(!showAddForm);
                  setEditingId(null);
                  setFormData({
                    description: '',
                    amount: '',
                    category: 'food',
                    date: new Date().toISOString().split('T')[0],
                    notes: ''
                  });
                }}
                className="flex items-center gap-2 bg-blue-600 hover:bg-blue-700 text-white px-4 py-2 rounded-lg transition"
              >
                <PlusCircle />
                Add Expense
              </button>
            </div>
          </div>
        </div>

        {/* Add/Edit Form */}
        {showAddForm && (
          <div className="bg-white/10 backdrop-blur-lg rounded-xl p-6 border border-white/20 mb-6">
            <h3 className="text-xl font-semibold text-white mb-4">
              {editingId ? 'Edit Expense' : 'Add New Expense'}
            </h3>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <input
                type="text"
                placeholder="Description"
                value={formData.description}
                onChange={(e) => setFormData({...formData, description: e.target.value})}
                required
                className="bg-white/20 text-white placeholder-blue-200 border border-white/30 rounded-lg px-4 py-2 focus:outline-none focus:ring-2 focus:ring-blue-500"
              />

              <input
                type="number"
                step="0.01"
                placeholder="Amount"
                value={formData.amount}
                onChange={(e) => setFormData({...formData, amount: e.target.value})}
                required
                className="bg-white/20 text-white placeholder-blue-200 border border-white/30 rounded-lg px-4 py-2 focus:outline-none focus:ring-2 focus:ring-blue-500"
              />

              <select
                value={formData.category}
                onChange={(e) => setFormData({...formData, category: e.target.value})}
                className="bg-white/20 text-white border border-white/30 rounded-lg px-4 py-2 focus:outline-none focus:ring-2 focus:ring-blue-500"
              >
                {categories.map(cat => (
                  <option key={cat.value} value={cat.value}>{cat.label}</option>
                ))}
              </select>

              <input
                type="date"
                value={formData.date}
                onChange={(e) => setFormData({...formData, date: e.target.value})}
                required
                className="bg-white/20 text-white border border-white/30 rounded-lg px-4 py-2 focus:outline-none focus:ring-2 focus:ring-blue-500"
              />

              <input
                type="text"
                placeholder="Notes (optional)"
                value={formData.notes}
                onChange={(e) => setFormData({...formData, notes: e.target.value})}
                className="bg-white/20 text-white placeholder-blue-200 border border-white/30 rounded-lg px-4 py-2 focus:outline-none focus:ring-2 focus:ring-blue-500 md:col-span-2"
              />

              <div className="md:col-span-2 flex gap-3">
                <button
                  onClick={handleSubmit}
                  className="bg-blue-600 hover:bg-blue-700 text-white px-6 py-2 rounded-lg transition"
                >
                  {editingId ? 'Update' : 'Add'} Expense
                </button>
                <button
                  type="button"
                  onClick={() => {
                    setShowAddForm(false);
                    setEditingId(null);
                  }}
                  className="bg-gray-600 hover:bg-gray-700 text-white px-6 py-2 rounded-lg transition"
                >
                  Cancel
                </button>
              </div>
            </div>
          </div>
        )}

        {/* Expenses List */}
        <div className="bg-white/10 backdrop-blur-lg rounded-xl border border-white/20 overflow-hidden">
          <div className="p-6 border-b border-white/20">
            <h3 className="text-xl font-semibold text-white">Recent Transactions</h3>
          </div>

          <div className="overflow-x-auto">
            {filteredExpenses.length === 0 ? (
              <div className="p-12 text-center text-blue-200">
                No expenses found. Add your first expense to get started!
              </div>
            ) : (
              <table className="w-full">
                <thead className="bg-white/5">
                  <tr>
                    <th className="text-left p-4 text-blue-200 font-semibold">Date</th>
                    <th className="text-left p-4 text-blue-200 font-semibold">Description</th>
                    <th className="text-left p-4 text-blue-200 font-semibold">Category</th>
                    <th className="text-right p-4 text-blue-200 font-semibold">Amount</th>
                    <th className="text-right p-4 text-blue-200 font-semibold">Actions</th>
                  </tr>
                </thead>
                <tbody>
                  {filteredExpenses.map((expense) => (
                    <tr key={expense.id} className="border-t border-white/10 hover:bg-white/5 transition">
                      <td className="p-4 text-white">
                        {new Date(expense.date).toLocaleDateString()}
                      </td>
                      <td className="p-4 text-white">
                        <div>{expense.description}</div>
                        {expense.notes && (
                          <div className="text-sm text-blue-300">{expense.notes}</div>
                        )}
                      </td>
                      <td className="p-4">
                        <span
                          className="inline-block px-3 py-1 rounded-full text-sm text-white"
                          style={{ backgroundColor: categories.find(c => c.value === expense.category)?.color }}
                        >
                          {categories.find(c => c.value === expense.category)?.label}
                        </span>
                      </td>
                      <td className="p-4 text-right text-white font-semibold">
                        ${expense.amount.toFixed(2)}
                      </td>
                      <td className="p-4 text-right">
                        <div className="flex gap-2 justify-end">
                          <button
                            onClick={() => handleEdit(expense)}
                            className="text-blue-400 hover:text-blue-300 transition"
                          >
                            <Edit3 />
                          </button>
                          <button
                            onClick={() => handleDelete(expense.id)}
                            className="text-red-400 hover:text-red-300 transition"
                          >
                            <Trash2 />
                          </button>
                        </div>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

export default ExpensesTracker;
